using Microsoft.AspNetCore.Authorization;using Microsoft.AspNetCore.Mvc;using verii_metivon_api.Modules.Pricing.Application.Services;namespace verii_metivon_api.Modules.Pricing.Api;[ApiController,Authorize,Route("api/pricing")]public sealed class PricingController(IPricingService s):ControllerBase{[HttpGet("price-lists")]public async Task<IActionResult>List([FromQuery]PricingQuery q,CancellationToken ct){var r=await s.GetPagedAsync(q,ct);return StatusCode(r.StatusCode,r);}[HttpPost("price-lists")]public async Task<IActionResult>Create(SavePriceListRequest x,CancellationToken ct){var r=await s.CreateAsync(x,ct);return StatusCode(r.StatusCode,r);}[HttpPost("price-lists/{id:long}/lines")]public async Task<IActionResult>Line(long id,SavePriceListLineRequest x,CancellationToken ct){var r=await s.AddLineAsync(id,x,ct);return StatusCode(r.StatusCode,r);}[HttpPost("calculate")]public async Task<IActionResult>Calculate(PriceRequest x,CancellationToken ct){var r=await s.CalculateAsync(x,ct);return StatusCode(r.StatusCode,r);}}
